1168	// the source is not yet bound. It reads the copy-on-write binding map with a single lock-free
1169	// Load, so the concentrator receive hot path never takes m.mu (see peerBySource).
1170	func (m *Multipath) lookupPeerBySource(addr netip.Addr) (*peerState, bool) {
1171		mp := m.peerBySource.Load()
1172		if mp == nil {
1173			return nil, false
1174		}
1175		p, ok := (*mp)[addr]
1176		return p, ok
