1179	// bindSourceToPeer records addr→p in the source-demux map, installed lock-free by a CAS
1180	// republish of a copy with the entry added (T88). It takes NO lock: a reader must never block
1181	// on m.mu (Close waits on the readers WHILE holding m.mu), so the binding — written from a
1182	// readLoop goroutine — must not acquire it. Idempotent: an already-present addr→p binding is a
1183	// no-op, and a lost CAS (a concurrent bind on another socket) simply retries. Copy-on-write
1184	// keeps every published map immutable, so a concurrent lookupPeerBySource over the old snapshot
1185	// is never disturbed.
1186	func (m *Multipath) bindSourceToPeer(addr netip.Addr, p *peerState) {
1187		for {
1188			old := m.peerBySource.Load()
1189			if old != nil {
1190				if existing, ok := (*old)[addr]; ok && existing == p {
1191					return
1192				}
1193			}
1194			var n int
1195			if old != nil {
1196				n = len(*old)
1197			}
1198			next := make(map[netip.Addr]*peerState, n+1)
1199			if old != nil {
1200				for k, v := range *old {
1201					next[k] = v
1202				}
1203			}
1204			next[addr] = p
1205			if m.peerBySource.CompareAndSwap(old, &next) {
1206				return
1207			}
