1213	// it routes to that peer's resequencer / FEC decoder / reflector. The source demux in
1214	// demuxInbound has already selected ps so a shared socket serving many peers resequences each
1215	// peer's stream against that peer's own buffer; on the single-peer edge/hub ps.peer is the
1216	// embedded primary, so this is byte-identical to the pre-split singleton. raw is retained for
1217	// the probe transport (HandleEcho / Reflect re-decode it under the peer's psk).
1218	func (m *Multipath) dispatchInbound(ps *peerPathState, fr frame.Frame, raw []byte, srcAP netip.AddrPort) {
1219		pr := ps.peer
