1235				// it present in the post-recovery loss estimator. A seq never marked here nor via
1236				// a reconstruction below is loss that FEC did not mask.
1237				if fr.connLoss != nil {
1238					fr.connLoss.Observe(f.OuterSeq)
1239				}
1240				m.observeRecovered(fr, rq, recovered, srcAP)
1241			} else {
1242				rq.Observe(f.OuterSeq, f.Payload, srcAP)
1243			}
1244		case frame.Parity:
