154			// The primary is index 0 in the per-socket view set, so a PROBE that verifies under the
155			// PRIMARY's psk must bind to the primary and the loop must STOP there — peer B (index 1)
156			// is never consulted, so it neither reflects nor learns a remote.
157			m, primary, second := twoPeerConcentrator(t, pskA, pskB)
158			secondView := peerPathByName(second, "a")
159			peer, peerAP := rawPeer(t)
